meta-properties.dotnet11-properties:
					
//Cargo el Organigrama
ORGANIGRAMA org=ORGANIGRAMA.Get(oi_organigrama,false);

int max=0;
foreach(NucleusWF.Base.Definicion.Organigramas.ROLE cur in org.ROLES)
{
	if (Nomad.NSystem.Functions.StringUtil.str2int(cur.c_role)>max) 
		max=Nomad.NSystem.Functions.StringUtil.str2int(cur.c_role);
}

ROLE retval=new ROLE();
retval.c_role  =(max+1).ToString();
retval.d_role  ="";
retval.l_unique=false;
retval.d_color ="FFFFFF";

return retval;

					
ROLE MyROLE=ROLE.Get(oid);        

//Obtengo el Organigrama PADRE
ORGANIGRAMA MyORG=ORGANIGRAMA.Get(MyROLE.oi_organigrama,false);

//Verifico si el ACTOR ESTA UTILIZADO.
int count=0;
foreach(ESTRUCTURA MyESTR in MyORG.ESTRUCTURA)
	if (MyESTR.c_role==MyROLE.c_role) 
		count++;

if (count!=0)   
	throw new NomadMessage("NucleusWF.ORG.USED", count.ToString());

//Eliminar
NomadEnvironment.GetCurrentTransaction().Delete(MyROLE);

